7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component is a generic Ping Pong buffer which consists in having
11	-- two buffers in a single RAM block that alternates. The system flips back
12	-- and forth between the buffers, letting run the algorithm on one buffer. Once
13	-- the number of samples to read is reached, the IRQ output is set to one
14	-- This allows acquiring constant data flow without losing, generally in use
15	-- when transfer occurs at lowest ratio than processing.
16	-- It is possible to send data in TDM mode or in parallel
17	-- ! Beware: if one channel preferably use parallel implementation
18	-- dat:--|---|---|xxx|xxx|xxx|---|---|---|xxx|xxx|xxx|---|---|---|xxx|xxx|xxx|
19	--       Ping        Pong        Ping        Pong        Ping        Pong
20	-- irq:          |           |           |           |           |           |
21	
22	library ieee;
23	use ieee.std_logic_1164.all;
24	use ieee.numeric_std.all;
25	
26	use work.psi_common_math_pkg.all;
27	
28	-- @formatter:off
29	entity psi_common_ping_pong is
30	  generic(ch_nb_g        : natural   := 16;                                                                  -- Channel number -> master 8
31	          depth_g        : natural   := 1012;                                                                -- sample number per memory space
32	          width_g        : positive  := 16;                                                                  -- data width in bits
33	          tdm_g          : boolean   := false;                                                               -- TDM* behavior if false PAR
34	          ram_behavior_g : string    := "RBW";                                                               -- ram behavior "RBW"|"WBR" -> cf RAM
35	          rst_pol_g      : std_logic := '1');                                                                -- reset polarity
36	  port(clk_i             : in  std_logic;                                                                    -- clock data
37	       rst_i             : in  std_logic;                                                                    -- rst data
38	       dat_i             : in  std_logic_vector(choose(tdm_g, width_g - 1, ch_nb_g * width_g - 1) downto 0); -- data input
39	       vld_i             : in  std_logic;                                                                    -- strobe input (ie valid)
40	       mem_irq_o         : out std_logic;                                                                    -- indicate when a set of buffer has been filled
41	       mem_clk_i         : in  std_logic;                                                                    -- clock mem
42	       mem_addr_ch_i     : in  std_logic_vector(log2ceil(ch_nb_g) - 1 downto 0);                             -- Channel selection for mem read
43	       mem_addr_spl_i    : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0);                             -- Sample selection for mem read
44	       mem_dat_o         : out std_logic_vector(width_g - 1 downto 0)                                        -- data mem read
45	      );
46	end entity;
47	-- @formatter:on
48	
49	architecture rtl of psi_common_ping_pong is
50	  -- internals
51	  constant ram_depth_c : integer := 2 * 2**log2ceil(ch_nb_g) * 2**(log2ceil(depth_g)); -- cst to define the ram depth
52	
53	  signal str_s, str_dff_s   : std_logic; -- pipe entry stage for strobe
54	  signal dpram_data_write_s : std_logic_vector(width_g - 1 downto 0); -- data to write within RAMs
55	  signal ch_offs_count_s    : unsigned(log2ceil(ch_nb_g) - 1 downto 0); -- channel counter <=> helper
56	  signal sample_s           : unsigned(log2ceil(depth_g) - 1 downto 0); -- sample counter  <=> base 	RAM address (LSB)
57	  signal dpram_add_s        : std_logic_vector(log2ceil(ram_depth_c) - 1 downto 0); -- RAMs address
58	  signal toggle_s           : std_logic; -- toggle bit for ping & pong
59	  signal cdc_toggle_s       : std_logic_vector(2 downto 0); -- select
60	  signal dpram_wren_s       : std_logic; -- write enable RAM1
61	  signal dpram_read_add_s   : std_logic_vector(log2ceil(ram_depth_c) - 1 downto 0) := (others => '0');
62	  signal dat_s              : std_logic_vector(width_g - 1 downto 0);
63	  --
64	  type data_array_t is array (0 to ch_nb_g - 1) of std_logic_vector(width_g - 1 downto 0);
65	  signal data_array_s       : data_array_t;
66	
67	begin
68	  --*** General ASSERT ***
69	  assert not (tdm_g and ch_nb_g = 1)
70	  report "###ERROR###: preferably use no tdm mode for one channel"
71	  severity failure;
72	
73	  --*** TAG Process CTRL ***
74	  proc_ctrl : process(clk_i)
75	  begin
76	    if rising_edge(clk_i) then
77	      if rst_i = rst_pol_g then
78	        --*** init ***
79	        sample_s        <= choose(tdm_g, to_unsigned(0, sample_s'length), to_unsigned(depth_g - 1, sample_s'length));
80	        toggle_s        <= '0';
81	        str_s           <= '0';
82	        str_dff_s       <= '0';
83	        dpram_wren_s    <= '0';
84	        ch_offs_count_s <= (others => '0');
85	        dpram_add_s     <= (others => '0');
86	
87	      else
88	
89	        str_s <= vld_i;
90	        --*** 1 pipe Entry gates PAR ***
91	        if not tdm_g then
92	          if ch_nb_g > 1 then
93	            for i in 0 to ch_nb_g - 1 loop
94	              data_array_s(i) <= dat_i(i * width_g + width_g - 1 downto i * width_g);
95	            end loop;
96	          else
97	            dat_s <= dat_i;
98	          end if;
99	        --*** 1 pipe Entry gates TDM ***
100	        else
101	          dat_s <= dat_i;
102	        end if;
103	
104	        --*** channel counter PAR ***
105	        if not tdm_g then
106	          if str_s = '1' then
107	            ch_offs_count_s <= (others => '0');
108	            str_dff_s       <= '1';
109	          else
110	            if ch_offs_count_s = ch_nb_g - 1 then
111	              ch_offs_count_s <= ch_offs_count_s;
112	              str_dff_s       <= '0';
113	            else
114	              ch_offs_count_s <= ch_offs_count_s + 1;
115	              str_dff_s       <= '1';
116	            end if;
117	          end if;
118	
119	        --*** channel counter TDM ***
120	        else
121	          if ch_offs_count_s = ch_nb_g - 1 then
122	            ch_offs_count_s <= (others => '0');
123	          else
124	            if str_s = '1' then
125	              ch_offs_count_s <= ch_offs_count_s + 1;
126	            end if;
127	          end if;
128	        end if;
129	
130	        --*** sample counter PAR ***
131	        if not tdm_g then
132	          if sample_s = depth_g - 1 and str_s = '1' then
133	            sample_s <= (others => '0');
134	            toggle_s <= not toggle_s;
135	          else
136	            if str_s = '1' then
137	              sample_s <= sample_s + 1;
138	            end if;
139	          end if;
140	        else
141	          if ch_offs_count_s = ch_nb_g - 1 and str_s = '1' then
142	            if sample_s = depth_g - 1 then
143	              sample_s <= (others => '0');
144	              toggle_s <= not toggle_s;
145	            else
146	              sample_s <= sample_s + 1;
147	            end if;
148	          end if;
149	        end if;
150	
151	        --*** DPRAM address write & ena ***
152	        dpram_add_s  <= toggle_s & std_logic_vector(ch_offs_count_s) & std_logic_vector(sample_s(sample_s'high downto 0));
153	        dpram_wren_s <= choose(tdm_g, str_s, str_dff_s);
154	
155	        --*** align data prior to write for PAR ***
156	        if not tdm_g then
157	          if ch_nb_g > 1 and str_dff_s = '1' then
158	            dpram_data_write_s             <= data_array_s(0);
159	            data_array_s(0 to ch_nb_g - 2) <= data_array_s(1 to ch_nb_g - 1);
160	          else
161	            dpram_data_write_s <= dat_s;
162	          end if;
163	        else
164	          --*** align data prior to write for TDM ***
165	          if str_s = '1' then
166	            dpram_data_write_s <= dat_s;
167	          end if;
168	        end if;
169	      end if;
170	    end if;
171	  end process;
172	
173	  --*** TAG cdc for toggle - double stage synchronizer ***
174	  proc_cdc : process(mem_clk_i)
175	  begin
176	    if rising_edge(mem_clk_i) then
177	      cdc_toggle_s(0) <= toggle_s;
178	      cdc_toggle_s(1) <= cdc_toggle_s(0);
179	      cdc_toggle_s(2) <= cdc_toggle_s(1);
180	    end if;
181	  end process;
182	  mem_irq_o        <= cdc_toggle_s(1) xor cdc_toggle_s(2);
183	  dpram_read_add_s <= not cdc_toggle_s(1) & mem_addr_ch_i & mem_addr_spl_i;
184	
185	  --*** TAG PING PONG Buffer ***
186	  inst_dpram_pp : entity work.psi_common_tdp_ram
187	    generic map(depth_g    => ram_depth_c,
188	                width_g    => width_g,
189	                behavior_g => ram_behavior_g)
190	    port map(a_clk_i  => clk_i,
191	             a_addr_i => dpram_add_s,
192	             a_wr_i   => dpram_wren_s,
193	             a_dat_i  => dpram_data_write_s,
194	             a_dat_o  => open,
195	             --
196	             b_clk_i  => mem_clk_i,
197	             b_addr_i => dpram_read_add_s,
198	             b_wr_i   => '0',
199	             b_dat_i  => (others => '0'),
200	             b_dat_o  => mem_dat_o);
201	
202	end architecture;
