19	entity psi_common_tdp_ram is
20	  generic(depth_g    : positive := 1024;                                                        -- mem depth in samples
21	          width_g    : positive := 32;                                                          -- data vector width in bits
22	          behavior_g : string   := "RBW");                                                      -- "RBW" = read-before-write, "WBR" = write-before-read
23	  port(   a_clk_i    : in  std_logic                                        := '0';             -- port a clock
24	          a_addr_i   : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0'); -- port a addr
25	          a_wr_i     : in  std_logic                                        := '0';             -- port a write enable acitve high
26	          a_dat_i    : in  std_logic_vector(width_g - 1 downto 0)           := (others => '0'); -- port a data input
27	          a_dat_o    : out std_logic_vector(width_g - 1 downto 0);                              -- port a data output                                                                           
28	          b_clk_i    : in  std_logic                                        := '0';             -- port b clock
29	          b_addr_i   : in  std_logic_vector(log2ceil(depth_g) - 1 downto 0) := (others => '0'); -- port b addr
30	          b_wr_i     : in  std_logic                                        := '0';             -- port b write enable active high
31	          b_dat_i    : in  std_logic_vector(width_g - 1 downto 0)           := (others => '0'); -- port b data input
32	          b_dat_o    : out std_logic_vector(width_g - 1 downto 0));                             -- port b data output
33	end entity;
34	-- @formatter:on
35	
36	architecture rtl of psi_common_tdp_ram is
37	
38	  -- memory array
39	  type mem_t is array (depth_g - 1 downto 0) of std_logic_vector(width_g - 1 downto 0);
40	  shared variable mem : mem_t := (others => (others => '0'));
41	
42	begin
43	
44	  assert behavior_g = "RBW" or behavior_g = "WBR" report "psi_common_tdp_ram: behavior_g must be RBW or WBR" severity error;
45	
46	  -- Port A
47	  porta_p : process(a_clk_i)
48	  begin
49	    if rising_edge(a_clk_i) then
50	      if behavior_g = "RBW" then
51	        a_dat_o <= mem(to_integer(unsigned(a_addr_i)));
52	      end if;
53	      if a_wr_i = '1' then
54	        mem(to_integer(unsigned(a_addr_i))) := a_dat_i;
55	      end if;
56	      if behavior_g = "WBR" then
57	        a_dat_o <= mem(to_integer(unsigned(a_addr_i)));
58	      end if;
59	    end if;
60	  end process;
61	
62	  -- Port B
63	  portb_p : process(b_clk_i)
64	  begin
65	    if rising_edge(b_clk_i) then
66	      if behavior_g = "RBW" then
67	        b_dat_o <= mem(to_integer(unsigned(b_addr_i)));
68	      end if;
69	      if b_wr_i = '1' then
70	        mem(to_integer(unsigned(b_addr_i))) := b_dat_i;
71	      end if;
72	      if behavior_g = "WBR" then
73	        b_dat_o <= mem(to_integer(unsigned(b_addr_i)));
74	      end if;
75	    end if;
76	  end process;
77	
78	end architecture;
