4	-- Authors: Benoit Stef
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	--This testbench verify if the ping pong buffer is able to manage different
11	--channel inputs with specific data frequency and number of sample to record.
12	--one assert is made to verify the nominal mechanism
13	--others asserts prevent misuses of the component    
14	
15	------------------------------------------------------------------------------
16	-- Libraries
17	------------------------------------------------------------------------------
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.numeric_std.all;
21	use ieee.math_real.all;
22	use std.textio.all;
23	
24	use work.psi_tb_activity_pkg.all;
25	use work.psi_common_math_pkg.all;
26	use work.psi_tb_compare_pkg.all;
27	
28	entity psi_common_ping_pong_tb is
29		generic(freq_data_clk_g : integer := 100E6; -- data clock frequency <=> Hz
30		        ratio_str_g     : integer := 10; -- ratio  between clock and data to write <=> clock cycle
31		        freq_mem_clk_g  : integer := 120E6; -- read clock frequency <=> Hz
32		        ch_nb_g         : natural := 4; -- number of channels <=> n/a
33		        sample_nb_g     : natural := 7; -- number of sample per buffer <=> n/a
34		        dat_length_g    : natural := 16; -- number of bit per data <=> n/a
35		        tdm_g           : boolean := true); -- using the buffer in time division multiplexed mode
36	end entity;
37	
38	architecture tb of psi_common_ping_pong_tb is
39	
40		constant period_w_c     : time                                                                     := (1 sec) / freq_data_clk_g;
41		constant period_r_c     : time                                                                     := (1 sec) / freq_mem_clk_g;
42		signal proc_clk_sti     : std_logic                                                                := '0';
43		signal mem_clk_sti      : std_logic                                                                := '1';
44		signal proc_rst_sti     : std_logic                                                                := '1';
45		signal proc_dat_par_sti : std_logic_vector(ch_nb_g * dat_length_g - 1 downto 0)                    := (others => 'L');
46		signal proc_dat_tdm_sti : std_logic_vector(dat_length_g - 1 downto 0)                              := (others => 'L');
47		signal proc_dat_sti     : std_logic_vector(choose(tdm_g, dat_length_g - 1, ch_nb_g * dat_length_g - 1) downto 0);
48		signal proc_str_s       : std_logic                                                                := '0';
49		signal proc_str_par_sti : std_logic                                                                := '0';
50		signal proc_str_tdm_sti : std_logic                                                                := '0';
51		signal proc_str_sti     : std_logic                                                                := '0';
52		signal mem_addr_s       : integer                                                                  := 0;
53		signal mem_addr_sti     : std_logic_vector(log2ceil(ch_nb_g) + log2ceil(sample_nb_g) - 1 downto 0) := (others => '0');
54		signal mem_addr_ch_sti  : std_logic_vector(log2ceil(ch_nb_g) - 1 downto 0)                         := (others => '0');
55		signal mem_addr_spl_sti : std_logic_vector(log2ceil(sample_nb_g) - 1 downto 0)                     := (others => '0');
56		signal mem_irq_obs      : std_logic;
57		signal mem_dat_obs      : std_logic_vector(dat_length_g - 1 downto 0);
58		signal mem_dat_check_s  : integer                                                                  := 0;
59		signal tb_run_s         : boolean                                                                  := true;
60		signal count_sample_s   : integer                                                                  := 0;
61		signal count_ch_s       : integer                                                                  := 0;
62		signal flag_s           : std_logic                                                                := '0';
63		signal count_sp_s       : integer                                                                  := 0;
64		type data_array_t is array (0 to ch_nb_g - 1) of std_logic_vector(dat_length_g - 1 downto 0);
65		signal data_array_s     : data_array_t                                                             := (others => (others => 'L'));
66	
67		--*** TAG resolution function to trasnform array of EXT_FORMAT_c to slv ***
68		function data_array_2_slv(signal data_i      : in data_array_t;
69		                          constant ch_number : natural) return std_logic_vector is
70			constant width_c : natural := dat_length_g;
71			variable data_v  : std_logic_vector(ch_number * width_c - 1 downto 0);
72		begin
73			for i in 0 to ch_number - 1 loop
74				data_v((i + 1) * width_c - 1 downto i * width_c) := data_i(i);
75			end loop;
76			return data_v;
77		end function;
78		--
79		signal check_s : integer := 0;
80	begin
81		--*** General ASSERTs to use the component properly***
82		assert (ch_nb_g <= ratio_str_g)
83		report "###ERROR###: The number of channel is too large comapred to the data strobe frequency"
84		severity failure;
85	
86		assert not (freq_data_clk_g = freq_mem_clk_g and ratio_str_g = 1)
87		report "###ERROR###: The data ratio and reading speeding clock are equivalent, it is not feasable"
88		severity failure;
89	
90		--*** TAG Reset generation ***
91		proc_rst : process
92		begin
93			wait for 3 * period_w_c;
94			wait until rising_edge(proc_clk_sti);
95			wait until rising_edge(proc_clk_sti);
96			proc_rst_sti <= '0';
97			wait until proc_str_tdm_sti = '1' and rising_edge(proc_clk_sti);
98			--*** Sync because latency created by par2tdm bloc ***
99			if tdm_g then
100				proc_rst_sti <= '1';
101				wait until rising_edge(proc_clk_sti);
102				wait until rising_edge(proc_clk_sti);
103				proc_rst_sti <= '0';
104			end if;
105			wait;
106		end process;
107	
108		--*** TAG clock process ***
109		proc_clk : process
110			variable tStop_v : time;
111		begin
112			while tb_run_s or (now < tStop_v + 1 us) loop
113				if tb_run_s then
114					tStop_v := now;
115				end if;
116				wait for 0.5 * period_w_c;
117				proc_clk_sti <= not proc_clk_sti;
118				wait for 0.5 * period_w_c;
119				proc_clk_sti <= not proc_clk_sti;
120			end loop;
121			wait;
122		end process;
123	
124		--*** TAG clock process ***
125		proc_mem_clk : process
126			variable tStop_v : time;
127		begin
128			while tb_run_s or (now < tStop_v + 1 us) loop
129				if tb_run_s then
130					tStop_v := now;
131				end if;
132				wait for 0.5 * period_r_c;
133				mem_clk_sti <= not mem_clk_sti;
134				wait for 0.5 * period_r_c;
135				mem_clk_sti <= not mem_clk_sti;
136			end loop;
137			wait;
138		end process;
139	
140		--*** TAG emulation Strobe/Valid for data input ***
141		proc_strob_tdm : process
142		begin
143			while tb_run_s loop
144				GenerateStrobe(real(freq_data_clk_g), real(freq_data_clk_g) / real(ratio_str_g),
145				               '1', proc_rst_sti, proc_clk_sti, proc_str_s);
146			end loop;
147			wait;
148		end process;
149		proc_str_par_sti <= transport proc_str_s after 2 * period_w_c;
150	
151		--*** PAR2TDM ***
152		tdm_gene : if tdm_g generate
153			par2tdm_inst : entity work.psi_common_par_tdm
154				generic map( rst_pol_g       => '1',
155				             ch_nb_g => ch_nb_g,
156				             ch_width_g => dat_length_g)
157				port map(clk_i         => proc_clk_sti,
158				         rst_i         => proc_rst_sti,
159				         dat_i         => proc_dat_par_sti,
160				         vld_i         => proc_str_par_sti,
161				         dat_o         => proc_dat_tdm_sti,
162				         vld_o         => proc_str_tdm_sti);
163		end generate;
164	
165		proc_dat_sti <= proc_dat_tdm_sti when tdm_g else proc_dat_par_sti;
166		proc_str_sti <= proc_str_tdm_sti when tdm_g else proc_str_par_sti;
167	
168		--*** convert int to slv for mem addr ***
169		mem_addr_sti <= std_logic_vector(to_unsigned(mem_addr_s, mem_addr_sti'length));
170	
171		--*** TAG DUT***
172		mem_addr_ch_sti  <= mem_addr_sti(mem_addr_sti'high downto mem_addr_spl_sti'length);
173		mem_addr_spl_sti <= mem_addr_sti(mem_addr_spl_sti'range);
174		inst_dut : entity work.psi_common_ping_pong
175			generic map(ch_nb_g        => ch_nb_g,
176			            depth_g    => sample_nb_g,
177			            width_g   => dat_length_g,
178			            tdm_g          => tdm_g,
179			            ram_behavior_g => "RBW", --fixed read before write
180			            rst_pol_g      => '1') --fixed active high
181			port map(clk_i          => proc_clk_sti,
182			         rst_i          => proc_rst_sti,
183			         dat_i          => proc_dat_sti,
184			         vld_i          => proc_str_sti,
185			         mem_irq_o      => mem_irq_obs,
186			         mem_clk_i      => mem_clk_sti,
187			         mem_addr_ch_i  => mem_addr_ch_sti,
188			         mem_addr_spl_i => mem_addr_spl_sti,
189			         mem_dat_o      => mem_dat_obs);
190	
191		--*** TAG stimuli process generate data to write ***
192		proc_stim_dat : process(proc_clk_sti)
193		begin
194			if rising_edge(proc_clk_sti) then
195				if proc_rst_sti = '1' then
196					data_array_s     <= (others => (others => '0'));
197					proc_dat_par_sti <= (others => '0');
198	
199				else
200					if proc_str_s = '1' then
201	
202						for i in 0 to ch_nb_g - 1 loop
203							data_array_s(i) <= std_logic_vector(to_unsigned((count_sample_s + i), dat_length_g));
204						end loop;
205	
206						if count_sample_s = sample_nb_g - 1 then
207							count_sample_s <= 0;
208						else
209							count_sample_s <= count_sample_s + 1;
210						end if;
211					end if;
212	
213					proc_dat_par_sti <= data_array_2_slv(data_array_s, ch_nb_g);
214				end if;
215			end if;
216		end process;
217	
218		--*** TAG process helper to check data read clock proc ***
219		proc_obs_dat : process(mem_clk_sti)
220		begin
221			if rising_edge(mem_clk_sti) then
222	
223				if flag_s = '1' then
224					--*** count for sample ***
225					if (sample_nb_g = (2**log2ceil(sample_nb_g)) and check_s = (2**log2ceil(sample_nb_g)-1)) or
226					   check_s > 2**log2ceil(sample_nb_g) - (2**log2ceil(sample_nb_g) - sample_nb_g) or
227					   count_sp_s = 2**log2ceil(sample_nb_g) - (2**log2ceil(sample_nb_g) - sample_nb_g) then
228						count_sp_s <= 0;
229					else
230						count_sp_s <= count_sp_s + 1;
231					end if;
232	
233					if check_s = 2**log2ceil(sample_nb_g) - 1 then
234						check_s    <= 0;
235						count_ch_s <= count_ch_s + 1;
236					else
237						check_s <= check_s + 1;
238					end if;
239	
240					if check_s >= sample_nb_g then
241						mem_dat_check_s <= 0;
242					else
243						mem_dat_check_s <= count_sp_s + count_ch_s;
244					end if;
245	
246				else
247					mem_dat_check_s <= 0;
248					count_ch_s      <= 0;
249					count_sp_s      <= 0;
250				end if;
251	
252			end if;
253		end process;
254	
255		--*** TAG check process ***
256		proc_check : process
257			variable lout_v : line;
258		begin
259			-------------------------------------------------------------------------------
260			write(lout_v, string'(" *************************************************  "));
261			writeline(output, lout_v);
262			write(lout_v, string'(" **          Paul Scherrer Institut             **  "));
263			writeline(output, lout_v);
264			write(lout_v, string'(" **         psi_common_pp_buf_tb TestBench      **  "));
265			writeline(output, lout_v);
266			write(lout_v, string'(" *************************************************  "));
267			writeline(output, lout_v);
268			-------------------------------------------------------------------------------
269			wait until mem_irq_obs = '1' and rising_edge(mem_clk_sti);
270	
271			for i in 0 to 7 loop
272				wait until mem_irq_obs = '1' and rising_edge(mem_clk_sti);
273				report "Burst Read Start" severity note;
274	
275				wait until rising_edge(mem_clk_sti);
276				wait until rising_edge(mem_clk_sti);
277	
278				for i in 0 to ch_nb_g * 2**log2ceil(sample_nb_g) - 1 loop
279					flag_s     <= '1';
280					wait until rising_edge(mem_clk_sti);
281					mem_addr_s <= mem_addr_s + 1;
282					--*** check value, it does then check sample and channel alignment ***
283					assert mem_dat_check_s = to_integer(unsigned(mem_dat_obs)) report "###ERROR###: data expected is wrong" severity error;
284				end loop;
285				mem_addr_s <= 0;
286				flag_s     <= '0';
287			end loop;
288	
289			wait for period_w_c;
